package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNull() throws Exception {
        // Create CSVFormat instance with escapeCharacter = null using reflection
        CSVFormat format = CSVFormat.newFormat(',');
        // Using reflection to set private final field escapeCharacter to null
        java.lang.reflect.Field field = CSVFormat.class.getDeclaredField("escapeCharacter");
        field.setAccessible(true);
        field.set(format, null);

        assertFalse(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsSet() throws Exception {
        // Create CSVFormat instance with escapeCharacter set to backslash
        CSVFormat format = CSVFormat.newFormat(',');
        // Using reflection to set private final field escapeCharacter to '\\'
        java.lang.reflect.Field field = CSVFormat.class.getDeclaredField("escapeCharacter");
        field.setAccessible(true);
        field.set(format, '\\');

        assertTrue(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSetUsingWithEscapeCharMethod() {
        CSVFormat format = CSVFormat.newFormat(',').withEscape('\\');
        assertTrue(format.isEscapeCharacterSet());
    }

    @Test
    void testIsEscapeCharacterSetUsingWithEscapeCharacterNull() {
        CSVFormat format = CSVFormat.newFormat(',').withEscape((Character) null);
        assertFalse(format.isEscapeCharacterSet());
    }
}
